// Récupération des données brutes
const inputData = $input.item.json;

// Gestion intelligente : si les données sont dans 'body', on prend 'body', sinon on prend la racine
const payload = inputData.body ? inputData.body : inputData;

// Validation
if (!payload.transaction_id || !payload.receipt_number) {
  throw new Error('Missing required fields: transaction_id or receipt_number');
}

if (payload.calendar_accepted === true) {
  throw new Error('Calendar transactions do not generate fiscal receipts');
}

if (payload.amount < 6) {
  throw new Error('Amount must be >= 6€ for fiscal receipt');
}

// Return clean data structure
return {
  transactionId: payload.transaction_id,
  receiptNumber: payload.receipt_number,
  amount: parseFloat(payload.amount),
  paymentMethod: payload.payment_method,
  createdAt: payload.created_at,
  donor: {
    email: payload.donor.email,
    name: payload.donor.name || `${payload.donor.first_name || ''} ${payload.donor.last_name || ''}`.trim(),
    firstName: payload.donor.first_name,
    lastName: payload.donor.last_name,
    address: payload.donor.address,
    zip: payload.donor.zip,
    city: payload.donor.city
  },
  receiptUrl: payload.receipt_url,
  userId: payload.user_id,
  tourneeId: payload.tournee_id
};

// 1. Récupération et validation des données
const transaction = $input.item.json;

// Sécurité : on vérifie qu'on a bien reçu une transaction
if (!transaction || !transaction.id) {
  throw new Error('Transaction not found in Supabase (ID manquant)');
}

// On récupère les données formatées du nœud précédent pour avoir les jolis noms
const extractedData = $('Extract & Validate Data').first().json;

// 2. Calculs métier
const taxReduction = (extractedData.amount * 0.66).toFixed(2);
const date = new Date(extractedData.createdAt);
const formattedDate = date.toLocaleDateString('fr-FR', { year: 'numeric', month: 'long', day: 'numeric' });

// 3. Construction du HTML (Optimisé 1 Page)
const html = `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <style>
    @page { margin: 0; }
    body {
      font-family: 'Helvetica', 'Arial', sans-serif;
      margin: 0;
      padding: 40px 50px;
      color: #1f2937;
      font-size: 13px;
      line-height: 1.5;
      background: white;
    }

    /* Header avec Logo */
    .header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 40px;
      border-bottom: 3px solid #b91c1c;
      padding-bottom: 20px;
    }
    .logo-container {
      display: flex;
      align-items: center;
      gap: 15px;
    }
    .logo-img {
      height: 80px; /* Taille idéale pour le logo */
      width: auto;
    }
    .org-title {
      font-size: 18px;
      font-weight: bold;
      color: #b91c1c;
      line-height: 1.2;
    }
    .receipt-info {
      text-align: right;
    }
    .receipt-info h1 {
      margin: 0;
      font-size: 28px;
      text-transform: uppercase;
      color: #111;
    }
    .receipt-number {
      font-size: 14px;
      color: #6b7280;
      font-weight: bold;
      margin-top: 5px;
    }

    /* Cerfa Box */
    .cerfa {
      background: #f3f4f6;
      padding: 12px 20px;
      border-radius: 6px;
      font-size: 11px;
      color: #4b5563;
      margin-bottom: 30px;
      border-left: 4px solid #b91c1c;
    }

    /* Grille Bénéficiaire / Donateur */
    .grid {
      display: flex;
      gap: 40px;
      margin-bottom: 40px;
    }
    .col {
      flex: 1;
    }
    .box-title {
      font-size: 11px;
      text-transform: uppercase;
      font-weight: bold;
      color: #9ca3af;
      margin-bottom: 8px;
      border-bottom: 1px solid #e5e7eb;
      padding-bottom: 4px;
    }
    .box-content {
      font-size: 14px;
    }
    .box-content strong {
      display: block;
      font-size: 15px;
      margin-bottom: 4px;
      color: #111;
    }

    /* Zone Montant */
    .amount-box {
      background: linear-gradient(135deg, #b91c1c 0%, #991b1b 100%);
      color: white;
      padding: 25px;
      border-radius: 12px;
      text-align: center;
      margin-bottom: 30px;
      box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
    }
    .amount-label {
      font-size: 14px;
      text-transform: uppercase;
      opacity: 0.9;
      letter-spacing: 1px;
    }
    .amount-value {
      font-size: 42px;
      font-weight: 800;
      margin: 10px 0;
    }
    .amount-details {
      font-size: 13px;
      opacity: 0.9;
      border-top: 1px solid rgba(255,255,255,0.2);
      display: inline-block;
      padding-top: 10px;
      margin-top: 5px;
    }

    /* Info Fiscale */
    .fiscal-info {
      border: 1px solid #e5e7eb;
      padding: 20px;
      border-radius: 8px;
      margin-bottom: 40px;
      font-size: 12px;
      color: #4b5563;
    }
    .fiscal-highlight {
      color: #b91c1c;
      font-weight: bold;
    }

    /* Signature */
    .footer-row {
      display: flex;
      justify-content: flex-end;
    }
    .signature-block {
      text-align: center;
      width: 250px;
    }
    .location {
      font-size: 13px;
      margin-bottom: 15px;
    }
    .role {
      font-weight: bold;
      font-size: 14px;
      margin-top: 50px; /* Espace pour signer si pas d'image */
      border-top: 1px solid #333;
      padding-top: 10px;
    }

    /* Pied de page */
    .legal-footer {
      margin-top: 60px;
      text-align: center;
      font-size: 10px;
      color: #9ca3af;
      border-top: 1px solid #f3f4f6;
      padding-top: 20px;
    }
  </style>
</head>
<body>

  <div class="header">
    <div class="logo-container">
      <img src="https://npyfregghvnmqxwgkfea.supabase.co/storage/v1/object/public/logo/logo_amicale.png" class="logo-img" alt="Logo Amicale">
      <div class="org-title">
        AMICALE DES<br>SAPEURS-POMPIERS<br>DE CLERMONT
      </div>
    </div>
    <div class="receipt-info">
      <h1>REÇU FISCAL</h1>
      <div class="receipt-number">Réf. ${extractedData.receiptNumber}</div>
    </div>
  </div>

  <div class="cerfa">
    <strong>Article 200 du Code Général des Impôts</strong><br>
    Reçu au titre des dons à certains organismes d'intérêt général habilités à délivrer des reçus fiscaux.
  </div>

  <div class="grid">
    <div class="col">
      <div class="box-title">Organisme Bénéficiaire</div>
      <div class="box-content">
        <strong>Amicale SP Clermont</strong>
        Centre de Secours<br>
        34800 Clermont-l'Hérault<br>
        <span style="color: #666; font-size: 12px;">Association Loi 1901 - But non lucratif</span>
      </div>
    </div>
    <div class="col">
      <div class="box-title">Donateur</div>
      <div class="box-content">
        <strong>${extractedData.donor.name || 'Non renseigné'}</strong>
        ${extractedData.donor.address || ''}<br>
        ${extractedData.donor.zip || ''} ${extractedData.donor.city || ''}<br>
        <span style="color: #666;">${extractedData.donor.email}</span>
      </div>
    </div>
  </div>

  <div class="amount-box">
    <div class="amount-label">Montant du Don</div>
    <div class="amount-value">${extractedData.amount.toFixed(2)} €</div>
    <div class="amount-details">
      Reçu le ${formattedDate} &nbsp;•&nbsp; Moyen de paiement : ${
  ['card', 'carte', 'cb', 'stripe', 'carte_bancaire'].includes((extractedData.paymentMethod || '').toLowerCase()) ? 'Carte Bancaire' :
  ['cash', 'especes', 'esp', 'liquide'].includes((extractedData.paymentMethod || '').toLowerCase()) ? 'Espèces' :
  ['cheque', 'chq'].includes((extractedData.paymentMethod || '').toLowerCase()) ? 'Chèque' :
  (extractedData.paymentMethod || 'Non spécifié')
}
    </div>
  </div>

  <div class="fiscal-info">
    <p style="margin: 0 0 10px 0;">
      L'Amicale certifie que ce don n'a aucune contrepartie directe ou indirecte sous forme de bien ou de prestation de services.
    </p>
    <p style="margin: 0;">
      👉 Ce don ouvre droit à une réduction d'impôt de <strong>66%</strong>, soit une économie fiscale de <span class="fiscal-highlight">${taxReduction} €</span>.
      Coût réel après réduction : <strong>${(extractedData.amount - parseFloat(taxReduction)).toFixed(2)} €</strong>.
    </p>
  </div>

  <div class="footer-row">
    <div class="signature-block">
      <div class="location">Fait à Clermont-l'Hérault, le ${formattedDate}</div>
      <!-- <img src="URL_SIGNATURE" style="height: 50px; display: block; margin: 0 auto;"> -->
      <div class="role">Le Président</div>
    </div>
  </div>

  <div class="legal-footer">
    Document généré automatiquement via n8n - Ne pas jeter sur la voie publique - Transaction ID: ${extractedData.transactionId}
  </div>

</body>
</html>`;

// Conversion binaire pour le nœud Gotenberg suivant
const buffer = Buffer.from(html, 'utf8');
const base64Data = buffer.toString('base64');

// On retourne directement le binaire pour simplifier (plus besoin du nœud "Convert to Binary" après)
// Mais si tu veux garder ton nœud séparé, retourne juste { html } ici.
return {
  html, // Pour debug
  transaction: extractedData
};

// Récupération des données
const items = $input.all();
const htmlContent = items[0].json.html; // <--- CORRIGÉ ICI (html au lieu de htmlContent)

if (!htmlContent) {
  throw new Error('HTML manquant dans les données (vérifier la sortie du nœud précédent)');
}

// Conversion en binaire pour Gotenberg
const buffer = Buffer.from(htmlContent, 'utf8');
const base64Data = buffer.toString('base64');

return [{
  json: items[0].json, // On garde les métadonnées (transactionId, etc.)
  binary: {
    data: {
      data: base64Data,
      fileName: "index.html", // Gotenberg a besoin de ce nom spécifique
      mimeType: "text/html"
    }
  }
}];
